import{_ as o}from"./chunks/lablededit.6MKmj5Mq.js";import{_ as t,a,b as s}from"./chunks/statusbar.BA8GrhQZ.js";import{_ as i}from"./chunks/trackbar.LGCXX873.js";import{_ as e,o as l,c as n,ae as g}from"./chunks/framework.C00B0EYs.js";const S=JSON.parse('{"title":"编辑器工作区","description":"理解编辑器的主要区域与核心交互方式。","frontmatter":{"title":"编辑器工作区","description":"理解编辑器的主要区域与核心交互方式。"},"headers":[],"relativePath":"zh/docs/guide/editor.md","filePath":"zh/docs/guide/editor.md"}'),c={name:"zh/docs/guide/editor.md"};function d(p,r,_,u,h,m){return l(),n("div",null,[...r[0]||(r[0]=[g('<h1 id="编辑器工作区" tabindex="-1">编辑器工作区 <a class="header-anchor" href="#编辑器工作区" aria-label="Permalink to &quot;编辑器工作区&quot;">​</a></h1><p>编辑器工作区是 Motor Sound Editor 的核心操作环境。在这里，你可以管理多条声音轨道、分配音频资源，并通过曲线图表精细调整列车在不同牵引（Traction）与制动（Brake）状态下的音高（Pitch）与音量（Volume）变化。</p><p><img src="'+o+'" alt="标注编辑页面"></p><p>工作区采用模块化布局，主要分为以下四个区域：</p><ol><li><strong>工具栏（Toolbar）</strong>：提供全局工具模式切换与项目操作。</li><li><strong>轨道侧栏（Track Sidebar）</strong>：位于右侧，用于管理轨道、音频文件与轨道状态。</li><li><strong>主图表工作区（Workspace）</strong>：位于中央，用于曲线编辑与关键帧操作。</li><li><strong>底部状态栏（Status Bar）</strong>：位于底部，用于实时试听与速度、状态控制。</li></ol><h2 id="_1-工具栏-toolbar" tabindex="-1">1. 工具栏（Toolbar） <a class="header-anchor" href="#_1-工具栏-toolbar" aria-label="Permalink to &quot;1. 工具栏（Toolbar）&quot;">​</a></h2><p>顶部工具栏包含会影响整个工作区交互方式的全局控制项。</p><p><img src="'+t+'" alt="工具"></p><ul><li><strong>工具模式（Tool Mode）</strong>：决定你如何与关键帧和曲线交互。 <ul><li><strong>选择工具（Select）</strong>：默认模式，用于选中关键帧。</li><li><strong>移动工具（Move）</strong>：用于拖拽已选中的关键帧，改变位置与数值。</li><li><strong>关键帧工具（Keyframe）</strong>：在曲线上左键插入关键帧，或右键快速删除关键帧。</li></ul></li><li><strong>吸附（Snap）</strong>：按住 <code>Shift</code> 可临时启用吸附。当前默认会将速度吸附到 <code>0.5</code> 的倍数，将数值吸附到 <code>0.2</code> 的倍数。</li></ul><h2 id="_2-轨道侧栏-track-sidebar" tabindex="-1">2. 轨道侧栏（Track Sidebar） <a class="header-anchor" href="#_2-轨道侧栏-track-sidebar" aria-label="Permalink to &quot;2. 轨道侧栏（Track Sidebar）&quot;">​</a></h2><p>侧栏结合了图层管理与混音思路，用于组织所有参与合成的电机音轨。</p><p><img src="'+i+'" alt="轨道侧栏"></p><ul><li><strong>轨道列表（Track List）</strong>：显示当前项目中的全部轨道。点击任意轨道即可将其设为 <strong>活动轨道（Active Track）</strong>，主图表会同步显示该轨道的曲线。</li><li><strong>资源分配（Asset Assignment）</strong>：你可以为每条轨道分配或替换本地音频文件。</li><li><strong>轨道状态控制（Track Controls）</strong>： <ul><li><strong>可见性（Show / Hide）</strong>：切换该轨道在图表中的显示状态。</li><li><strong>静音（Mute）</strong>：在试听时暂时屏蔽该轨道的声音。</li></ul></li></ul><h2 id="_3-主图表工作区-workspace" tabindex="-1">3. 主图表工作区（Workspace） <a class="header-anchor" href="#_3-主图表工作区-workspace" aria-label="Permalink to &quot;3. 主图表工作区（Workspace）&quot;">​</a></h2><p>这是编辑电机声音动态变化的核心区域。横轴通常代表速度，纵轴代表音高或音量。</p><p><img src="'+a+'" alt="工作区"></p><p>每条轨道都维护两套彼此独立的曲线环境：</p><ul><li><strong>牵引 / 制动（Traction / Brake）</strong>：用于分别描述加速与制动时的声音行为。</li><li><strong>音高曲线（Pitch）</strong>：控制不同速度下的播放速率或频率偏移。</li><li><strong>音量曲线（Volume）</strong>：控制不同速度区间内的响度变化。</li></ul><p>需要注意的是，当前项目数据只保存 <strong>Traction</strong> 和 <strong>Brake</strong> 两套专用曲线。试听时的 <strong>Coasting</strong> 仍沿用牵引侧曲线进行预览。</p><h2 id="_4-底部状态栏-status-bar" tabindex="-1">4. 底部状态栏（Status Bar） <a class="header-anchor" href="#_4-底部状态栏-status-bar" aria-label="Permalink to &quot;4. 底部状态栏（Status Bar）&quot;">​</a></h2><p>底部栏主要用于实时试听与状态控制。</p><p><img src="'+s+'" alt="底部状态栏"></p><ul><li><strong>播放 / 暂停（Play / Pause）</strong>：启动或停止试听引擎。</li><li><strong>状态切换按钮</strong>：在 <strong>Traction</strong>、<strong>Coasting</strong> 和 <strong>Brake</strong> 之间切换，用于测试状态变化时的声音过渡。你也可以通过快捷键 <code>W</code> 与 <code>S</code> 切换。</li><li><strong>当前速度（Current Speed）</strong>：控制试听时的目标速度，便于在不同速度区间检查曲线效果。</li></ul>',23)])])}const P=e(c,[["render",d]]);export{S as __pageData,P as default};
